@Service
@RequiredArgsConstructor
@Slf4j
public class NotificationService {

    private final EmailService emailService;
    private final SmsService smsService;

    @Async("emailExecutor")
    public CompletableFuture<Void> sendOrderConfirmation(Order order) {
        try {
            emailService.send(order.getUser().getEmail(),
                "Order Confirmation", buildBody(order));
            return CompletableFuture.completedFuture(null);
        } catch (Exception e) {
            log.error("Failed to send order confirmation for {}", order.getId(), e);
            return CompletableFuture.failedFuture(e);
        }
    }

    @Async("taskExecutor")
    public CompletableFuture<Void> sendWelcomeNotifications(User user) {
        CompletableFuture<Void> email = CompletableFuture.runAsync(() ->
            emailService.send(user.getEmail(), "Welcome!", buildWelcome(user)));
        CompletableFuture<Void> sms = CompletableFuture.runAsync(() ->
            smsService.send(user.getPhone(), "Welcome to our service!"));
        return CompletableFuture.allOf(email, sms)
            .exceptionally(ex -> { log.error("Welcome notifications failed", ex); return null; });
    }
}
